{
  "name": "betshow",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc -b && vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "react": "^19.0.0",
    "react-dom": "^19.0.0"
  },
  "devDependencies": {
    "@types/react": "^19.0.0",
    "@types/react-dom": "^19.0.0",
    "@vitejs/plugin-react": "^4.3.4",
    "typescript": "~5.7.2",
    "vite": "^6.0.3"
  }
}

import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
});

import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import App from "./App";
import "./styles/global.css";

createRoot(document.getElementById("root")!).render(
  <StrictMode>
    <App />
  </StrictMode>
);

/* BetShow — Design System: cores vibrantes, tipografia marcante */

:root {
  /* Fundo & profundidade */
  --bg-deep: #050810;
  --bg-primary: #0a0e17;
  --bg-elevated: #121a2b;
  --bg-card: #161f35;
  --bg-glass: rgba(22, 31, 53, 0.72);

  /* Cores de impacto */
  --neon-green: #00ff87;
  --neon-green-dim: #00cc6a;
  --gold: #ffd700;
  --gold-soft: #ffb800;
  --magenta: #ff006e;
  --magenta-soft: #ff4d94;
  --cyan: #00d4ff;
  --electric-purple: #8b5cf6;
  --orange-fire: #ff6b35;

  /* Texto */
  --text-primary: #f4f7ff;
  --text-secondary: #a8b4d4;
  --text-muted: #6b7a9e;

  /* Gradientes */
  --gradient-hero: linear-gradient(
    135deg,
    #0a0e17 0%,
    #1a1035 40%,
    #0d2818 100%
  );
  --gradient-cta: linear-gradient(135deg, var(--neon-green) 0%, var(--cyan) 100%);
  --gradient-gold: linear-gradient(135deg, var(--gold) 0%, var(--orange-fire) 100%);
  --gradient-magenta: linear-gradient(135deg, var(--magenta) 0%, var(--electric-purple) 100%);

  /* Tipografia */
  --font-display: "Bebas Neue", sans-serif;
  --font-headline: "Syne", sans-serif;
  --font-body: "Outfit", sans-serif;

  /* Espaçamento & forma */
  --radius-sm: 8px;
  --radius-md: 14px;
  --radius-lg: 22px;
  --radius-pill: 999px;
  --shadow-glow-green: 0 0 40px rgba(0, 255, 135, 0.35);
  --shadow-glow-gold: 0 0 30px rgba(255, 215, 0, 0.3);
  --transition: 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-body);
  background: var(--bg-deep);
  color: var(--text-primary);
  line-height: 1.6;
  overflow-x: hidden;
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

button {
  font-family: inherit;
  cursor: pointer;
  border: none;
  background: none;
}

ul {
  list-style: none;
}

/* Utilitários */
.container {
  width: min(1200px, 92vw);
  margin-inline: auto;
}

.section-title {
  font-family: var(--font-headline);
  font-size: clamp(2rem, 5vw, 3.25rem);
  font-weight: 800;
  letter-spacing: -0.02em;
  line-height: 1.1;
}

.section-title span {
  background: var(--gradient-cta);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.section-sub {
  color: var(--text-secondary);
  font-size: 1.1rem;
  max-width: 560px;
  margin-top: 0.75rem;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 0.9rem 1.75rem;
  font-weight: 700;
  font-size: 0.95rem;
  border-radius: var(--radius-pill);
  transition: transform var(--transition), box-shadow var(--transition);
}

.btn:hover {
  transform: translateY(-2px);
}

.btn-primary {
  background: var(--gradient-cta);
  color: var(--bg-deep);
  box-shadow: var(--shadow-glow-green);
}

.btn-primary:hover {
  box-shadow: 0 0 50px rgba(0, 255, 135, 0.5);
}

.btn-gold {
  background: var(--gradient-gold);
  color: var(--bg-deep);
  box-shadow: var(--shadow-glow-gold);
}

.btn-outline {
  border: 2px solid rgba(0, 255, 135, 0.5);
  color: var(--neon-green);
  background: transparent;
}

.btn-outline:hover {
  background: rgba(0, 255, 135, 0.1);
}

/* Animações */
@keyframes float {
  0%,
  100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-12px);
  }
}

@keyframes pulse-glow {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.7;
  }
}

@keyframes marquee {
  0% {
    transform: translateX(0);
  }
  100% {
    transform: translateX(-50%);
  }
}

@keyframes shimmer {
  0% {
    background-position: -200% center;
  }
  100% {
    background-position: 200% center;
  }
}

/* Grid decorativo de fundo */
.bg-grid {
  background-image:
    linear-gradient(rgba(0, 255, 135, 0.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0, 255, 135, 0.03) 1px, transparent 1px);
  background-size: 48px 48px;
}

/* Acessibilidade */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
  html {
    scroll-behavior: auto;
  }
}

import Header from "./components/Header";
import Hero from "./components/Hero";
import TrustBar from "./components/TrustBar";
import PromoCards from "./components/PromoCards";
import SportsArena from "./components/SportsArena";
import FamilyClub from "./components/FamilyClub";
import RegisterCPF from "./components/RegisterCPF";
import LiveOdds from "./components/LiveOdds";
import Footer from "./components/Footer";

export default function App() {
  return (
    <>
      <Header />
      <main>
        <Hero />
        <TrustBar />
        <PromoCards />
        <LiveOdds />
        <SportsArena />
        <FamilyClub />
        <RegisterCPF />
      </main>
      <Footer />
    </>
  );
}

.header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 100;
  padding: 0.85rem 0;
  background: rgba(5, 8, 16, 0.85);
  backdrop-filter: blur(16px);
  border-bottom: 1px solid rgba(0, 255, 135, 0.12);
}

.header__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1.5rem;
}

.header__logo {
  display: flex;
  align-items: center;
  gap: 0.65rem;
  flex-shrink: 0;
}

.header__logo-mark {
  font-family: var(--font-display);
  font-size: 1.5rem;
  width: 42px;
  height: 42px;
  display: grid;
  place-items: center;
  background: var(--gradient-cta);
  color: var(--bg-deep);
  border-radius: var(--radius-sm);
  letter-spacing: 0.02em;
}

.header__logo-text {
  font-family: var(--font-headline);
  font-weight: 800;
  font-size: 1.35rem;
  letter-spacing: -0.03em;
}

.header__logo-text span {
  color: var(--neon-green);
}

.header__nav {
  display: flex;
  gap: 1.75rem;
}

.header__link {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--text-secondary);
  transition: color var(--transition);
}

.header__link:hover {
  color: var(--neon-green);
}

.header__actions {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.header__login {
  padding: 0.65rem 1.25rem;
  font-size: 0.85rem;
}

@media (max-width: 900px) {
  .header__nav {
    display: none;
  }
}

@media (max-width: 520px) {
  .header__login {
    display: none;
  }
}

.hero {
  position: relative;
  min-height: 100vh;
  padding: 7rem 0 4rem;
  background: var(--gradient-hero);
  overflow: hidden;
}

.hero__glow {
  position: absolute;
  border-radius: 50%;
  filter: blur(100px);
  pointer-events: none;
}

.hero__glow--green {
  width: 500px;
  height: 500px;
  background: rgba(0, 255, 135, 0.15);
  top: -100px;
  right: 10%;
}

.hero__glow--magenta {
  width: 400px;
  height: 400px;
  background: rgba(255, 0, 110, 0.12);
  bottom: 20%;
  left: -5%;
}

.hero__inner {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3rem;
  align-items: center;
  position: relative;
  z-index: 1;
}

.hero__badge {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--cyan);
  background: rgba(0, 212, 255, 0.1);
  border: 1px solid rgba(0, 212, 255, 0.3);
  padding: 0.4rem 0.9rem;
  border-radius: var(--radius-pill);
  margin-bottom: 1.25rem;
}

.hero__badge-dot {
  width: 8px;
  height: 8px;
  background: var(--neon-green);
  border-radius: 50%;
  animation: pulse-glow 1.5s ease infinite;
}

.hero__title {
  font-family: var(--font-display);
  font-size: clamp(3.5rem, 8vw, 5.5rem);
  line-height: 0.95;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  margin-bottom: 1.25rem;
}

.hero__title-accent {
  display: block;
  background: var(--gradient-gold);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  filter: drop-shadow(0 0 30px rgba(255, 215, 0, 0.3));
}

.hero__desc {
  font-size: 1.15rem;
  color: var(--text-secondary);
  max-width: 480px;
  margin-bottom: 2rem;
}

.hero__desc strong {
  color: var(--gold);
}

.hero__ctas {
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  margin-bottom: 2.5rem;
}

.hero__cta-main {
  font-size: 1.05rem;
  padding: 1rem 2rem;
}

.hero__stats {
  display: flex;
  gap: 2.5rem;
  padding-top: 1.5rem;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
}

.hero__stats strong {
  display: block;
  font-family: var(--font-headline);
  font-size: 1.75rem;
  color: var(--neon-green);
}

.hero__stats span {
  font-size: 0.8rem;
  color: var(--text-muted);
}

.hero__visual {
  position: relative;
}

.hero__card {
  border-radius: var(--radius-lg);
  overflow: hidden;
  border: 2px solid rgba(0, 255, 135, 0.25);
  box-shadow: var(--shadow-glow-green), 0 24px 60px rgba(0, 0, 0, 0.5);
}

.hero__card img {
  width: 100%;
  height: 320px;
  object-fit: cover;
}

.hero__card-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 1.25rem;
  background: linear-gradient(transparent, rgba(5, 8, 16, 0.95));
}

.hero__card--main {
  position: relative;
}

.hero__live {
  display: inline-block;
  font-size: 0.7rem;
  font-weight: 800;
  letter-spacing: 0.1em;
  background: var(--magenta);
  color: white;
  padding: 0.2rem 0.5rem;
  border-radius: 4px;
  margin-bottom: 0.35rem;
  animation: pulse-glow 1.2s ease infinite;
}

.hero__card-overlay p {
  font-weight: 600;
  margin-bottom: 0.75rem;
}

.hero__odds {
  display: flex;
  gap: 0.5rem;
}

.hero__odds button {
  flex: 1;
  padding: 0.5rem;
  font-size: 0.8rem;
  font-weight: 700;
  background: var(--bg-elevated);
  color: var(--text-primary);
  border-radius: var(--radius-sm);
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all var(--transition);
}

.hero__odds button.active,
.hero__odds button:hover {
  background: var(--neon-green);
  color: var(--bg-deep);
  border-color: var(--neon-green);
}

.hero__float {
  position: absolute;
  display: flex;
  align-items: center;
  gap: 0.65rem;
  background: var(--bg-glass);
  backdrop-filter: blur(12px);
  border: 1px solid rgba(255, 215, 0, 0.35);
  padding: 0.75rem 1rem;
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-glow-gold);
  animation: float 4s ease-in-out infinite;
}

.hero__float span {
  font-size: 1.5rem;
}

.hero__float strong {
  display: block;
  font-family: var(--font-display);
  font-size: 1.5rem;
  color: var(--gold);
  line-height: 1;
}

.hero__float small {
  font-size: 0.7rem;
  color: var(--text-secondary);
}

.hero__float--bonus {
  top: -20px;
  left: -30px;
}

.hero__float--cash {
  bottom: 40px;
  right: -20px;
  animation-delay: 1s;
  border-color: rgba(0, 255, 135, 0.35);
}

.hero__float--cash strong {
  color: var(--neon-green);
}

.hero__ticker {
  margin-top: 3rem;
  overflow: hidden;
  border-top: 1px solid rgba(0, 255, 135, 0.15);
  padding-top: 1rem;
}

.hero__ticker-track {
  display: flex;
  white-space: nowrap;
  animation: marquee 25s linear infinite;
}

.hero__ticker-track span {
  font-family: var(--font-display);
  font-size: 1.25rem;
  letter-spacing: 0.15em;
  color: rgba(0, 255, 135, 0.4);
  padding-right: 2rem;
}

@media (max-width: 960px) {
  .hero__inner {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero__desc {
    margin-inline: auto;
  }

  .hero__ctas,
  .hero__stats {
    justify-content: center;
  }

  .hero__visual {
    max-width: 480px;
    margin-inline: auto;
  }
}

import "./TrustBar.css";

const TRUST_ITEMS = [
  {
    icon: "shield",
    title: "Site 100% seguro",
    desc: "SSL + criptografia ponta a ponta",
  },
  {
    icon: "cpf",
    title: "CPF verificado",
    desc: "KYC rápido e antifraude ativo",
  },
  {
    icon: "platform",
    title: "Plataforma 100%",
    desc: "Uptime garantido, sem quedas",
  },
  {
    icon: "gov",
    title: "Imposto GOV",
    desc: "Conformidade Lei 14.790/23",
  },
  {
    icon: "lock",
    title: "Apostas seguras",
    desc: "Limites responsáveis + autoexclusão",
  },
];

function TrustIcon({ type }: { type: string }) {
  const paths: Record<string, React.ReactNode> = {
    shield: (
      <path
        d="M12 2L4 6v6c0 5.5 3.8 10.7 8 12 4.2-1.3 8-6.5 8-12V6l-8-4z"
        stroke="currentColor"
        strokeWidth="1.5"
        fill="none"
      />
    ),
    cpf: (
      <>
        <rect x="4" y="5" width="16" height="14" rx="2" stroke="currentColor" strokeWidth="1.5" fill="none" />
        <path d="M8 10h8M8 14h5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
      </>
    ),
    platform: (
      <path
        d="M4 6h16v12H4V6zm0 4h16M8 6V4h8v2"
        stroke="currentColor"
        strokeWidth="1.5"
        fill="none"
        strokeLinecap="round"
      />
    ),
    gov: (
      <>
        <circle cx="12" cy="12" r="9" stroke="currentColor" strokeWidth="1.5" fill="none" />
        <path d="M12 7v5l3 2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
      </>
    ),
    lock: (
      <path
        d="M8 11V8a4 4 0 118 0v3M6 11h12v9H6v-9z"
        stroke="currentColor"
        strokeWidth="1.5"
        fill="none"
        strokeLinecap="round"
      />
    ),
  };
  return (
    <svg width="28" height="28" viewBox="0 0 24 24" aria-hidden>
      {paths[type]}
    </svg>
  );
}

export default function TrustBar() {
  return (
    <section className="trust" aria-label="Selos de confiança">
      <div className="container trust__grid">
        {TRUST_ITEMS.map((item) => (
          <article key={item.title} className="trust__item">
            <div className="trust__icon">
              <TrustIcon type={item.icon} />
            </div>
            <div>
              <h3>{item.title}</h3>
              <p>{item.desc}</p>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
}

.trust {
  padding: 2.5rem 0;
  background: var(--bg-primary);
  border-block: 1px solid rgba(0, 255, 135, 0.1);
}

.trust__grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 1.25rem;
}

.trust__item {
  display: flex;
  align-items: flex-start;
  gap: 0.85rem;
  padding: 1rem;
  border-radius: var(--radius-md);
  background: rgba(0, 255, 135, 0.04);
  border: 1px solid rgba(0, 255, 135, 0.12);
  transition: border-color var(--transition), transform var(--transition);
}

.trust__item:hover {
  border-color: rgba(0, 255, 135, 0.35);
  transform: translateY(-3px);
}

.trust__icon {
  flex-shrink: 0;
  width: 48px;
  height: 48px;
  display: grid;
  place-items: center;
  background: rgba(0, 255, 135, 0.12);
  border-radius: var(--radius-sm);
  color: var(--neon-green);
}

.trust__item h3 {
  font-size: 0.9rem;
  font-weight: 700;
  margin-bottom: 0.2rem;
}

.trust__item p {
  font-size: 0.75rem;
  color: var(--text-muted);
  line-height: 1.4;
}

@media (max-width: 1024px) {
  .trust__grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 480px) {
  .trust__grid {
    grid-template-columns: 1fr;
  }
}

import "./PromoCards.css";

const PROMOS = [
  {
    id: "bonus",
    tag: "Bônus",
    title: "Até R$ 500 no 1º depósito",
    desc: "Dobre sua banca com rollover justo. Código BETSHOW500 no cadastro.",
    gradient: "gold",
    figure: "🎯",
    cta: "Resgatar bônus",
  },
  {
    id: "cashback",
    tag: "Cashback",
    title: "15% de volta toda semana",
    desc: "Perdeu na rodada? Receba cashback automático na segunda-feira.",
    gradient: "green",
    figure: "♻️",
    cta: "Ativar cashback",
  },
  {
    id: "safe",
    tag: "Apostas seguras",
    title: "Proteção total da banca",
    desc: "Cash out antecipado, seguro de múltipla e limites personalizáveis.",
    gradient: "cyan",
    figure: "🛡️",
    cta: "Saiba mais",
  },
];

export default function PromoCards() {
  return (
    <section className="promos" id="bonus" aria-labelledby="promos-title">
      <div className="container">
        <header className="promos__header">
          <h2 id="promos-title" className="section-title">
            Vantagens que <span>prendem você</span>
          </h2>
          <p className="section-sub">
            Bônus agressivos, cashback real e ferramentas para apostar com
            inteligência — sem letras miúdas escondidas.
          </p>
        </header>

        <div className="promos__grid">
          {PROMOS.map((promo) => (
            <article
              key={promo.id}
              id={promo.id === "cashback" ? "cashback" : undefined}
              className={`promos__card promos__card--${promo.gradient}`}
            >
              <span className="promos__tag">{promo.tag}</span>
              <span className="promos__figure" aria-hidden>
                {promo.figure}
              </span>
              <h3>{promo.title}</h3>
              <p>{promo.desc}</p>
              <a href="#cadastro" className="promos__cta">
                {promo.cta}
                <span aria-hidden>→</span>
              </a>
              <div className="promos__shape" aria-hidden />
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

.promos {
  padding: 5rem 0;
  background: var(--bg-deep);
}

.promos__header {
  text-align: center;
  margin-bottom: 3rem;
}

.promos__header .section-sub {
  margin-inline: auto;
}

.promos__grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;
}

.promos__card {
  position: relative;
  padding: 2rem 1.75rem;
  border-radius: var(--radius-lg);
  background: var(--bg-card);
  border: 1px solid rgba(255, 255, 255, 0.08);
  overflow: hidden;
  transition: transform var(--transition), box-shadow var(--transition);
}

.promos__card:hover {
  transform: translateY(-6px);
}

.promos__card--gold:hover {
  box-shadow: var(--shadow-glow-gold);
  border-color: rgba(255, 215, 0, 0.4);
}

.promos__card--green:hover {
  box-shadow: var(--shadow-glow-green);
  border-color: rgba(0, 255, 135, 0.4);
}

.promos__card--cyan:hover {
  box-shadow: 0 0 40px rgba(0, 212, 255, 0.25);
  border-color: rgba(0, 212, 255, 0.4);
}

.promos__tag {
  display: inline-block;
  font-size: 0.7rem;
