/* Enquadramento close-up + degradê para fundir fotos no layout */

.photo-closeup {
  position: relative;
  overflow: hidden;
  isolation: isolate;
}

.photo-closeup img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center 18%;
  transform: scale(1.12);
  transition: transform 0.6s ease;
}

.photo-closeup:hover img {
  transform: scale(1.18);
}

/* Degradê lateral — funde com o fundo escuro */
.photo-closeup::before {
  content: "";
  position: absolute;
  inset: 0;
  z-index: 2;
  pointer-events: none;
}

.photo-closeup--fade-left::before {
  background: linear-gradient(
    105deg,
    var(--bg-deep) 0%,
    rgba(5, 8, 16, 0.85) 22%,
    rgba(5, 8, 16, 0.25) 48%,
    transparent 72%
  );
}

.photo-closeup--fade-right::before {
  background: linear-gradient(
    255deg,
    var(--bg-deep) 0%,
    rgba(5, 8, 16, 0.8) 25%,
    transparent 65%
  );
}

.photo-closeup--fade-bottom::after {
  content: "";
  position: absolute;
  inset: 0;
  z-index: 2;
  pointer-events: none;
  background: linear-gradient(
    to top,
    var(--bg-deep) 0%,
    rgba(5, 8, 16, 0.75) 18%,
    rgba(5, 8, 16, 0.2) 45%,
    transparent 68%
  );
}

/* Overlay colorido de marca */
.photo-closeup--tint-green::after {
  content: "";
  position: absolute;
  inset: 0;
  z-index: 1;
  background: linear-gradient(
    160deg,
    rgba(0, 255, 135, 0.35) 0%,
    transparent 40%,
    rgba(255, 0, 110, 0.2) 100%
  );
  mix-blend-mode: soft-light;
  pointer-events: none;
}

.photo-closeup--tint-gold::after {
  content: "";
  position: absolute;
  inset: 0;
  z-index: 1;
  background: linear-gradient(
    200deg,
