import type { ReactNode } from "react";
import "./PhotoCloseup.css";

type FadeSide = "left" | "right" | "bottom";
type Tint = "green" | "gold" | "magenta" | "none";
type Ring = "cta" | "gold" | "magenta" | "none";

type PhotoCloseupProps = {
  src: string;
  alt: string;
  height?: number | string;
  fades?: FadeSide[];
  tint?: Tint;
  ring?: Ring;
  className?: string;
  children?: ReactNode;
};

export default function PhotoCloseup({
  src,
  alt,
  height = 420,
  fades = ["left", "bottom"],
  tint = "green",
  ring = "none",
  className = "",
  children,
}: PhotoCloseupProps) {
  const h = typeof height === "number" ? `${height}px` : height;

  return (
    <div
      className={`photo-closeup photo-closeup--ring-${ring} ${className}`.trim()}
      style={{ ["--photo-h" as string]: h }}
    >
      <div className="photo-closeup__inner">
        <img src={src} alt={alt} loading="lazy" />
        {fades.includes("left") && <div className="photo-fade photo-fade--left" aria-hidden />}
        {fades.includes("right") && <div className="photo-fade photo-fade--right" aria-hidden />}
        {fades.includes("bottom") && <div className="photo-fade photo-fade--bottom" aria-hidden />}
        {tint !== "none" && (
          <div className={`photo-tint photo-tint--${tint}`} aria-hidden />
        )}
        {children && <div className="photo-closeup__content">{children}</div>}
      </div>
    </div>
  );
}

.photo-closeup {
  --photo-h: 420px;
  position: relative;
  border-radius: var(--radius-lg);
}

.photo-closeup--ring-cta {
  padding: 3px;
  background: var(--gradient-cta);
  border-radius: var(--radius-lg);
}

.photo-closeup--ring-gold {
  padding: 3px;
  background: var(--gradient-gold);
  border-radius: var(--radius-lg);
}

.photo-closeup--ring-magenta {
  padding: 3px;
  background: var(--gradient-magenta);
  border-radius: var(--radius-lg);
}

.photo-closeup__inner {
  position: relative;
  height: var(--photo-h);
  overflow: hidden;
  border-radius: calc(var(--radius-lg) - 3px);
}

.photo-closeup--ring-none .photo-closeup__inner {
  border-radius: var(--radius-lg);
}

.photo-closeup__inner img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center 15%;
  transform: scale(1.14);
  transition: transform 0.55s ease;
}

.photo-closeup:hover .photo-closeup__inner img {
  transform: scale(1.2);
}

.photo-fade {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 2;
}

.photo-fade--left {
  background: linear-gradient(
    100deg,
    var(--bg-deep) 0%,
    rgba(5, 8, 16, 0.9) 20%,
    rgba(5, 8, 16, 0.35) 45%,
    transparent 70%
  );
}

.photo-fade--right {
  background: linear-gradient(
    260deg,
    var(--bg-deep) 0%,
    rgba(5, 8, 16, 0.85) 28%,
    transparent 62%
  );
}

.photo-fade--bottom {
  background: linear-gradient(
    to top,
    var(--bg-deep) 0%,
    rgba(5, 8, 16, 0.8) 22%,
    rgba(5, 8, 16, 0.15) 50%,
    transparent 72%
  );
}

.photo-tint {
  position: absolute;
  inset: 0;
  z-index: 1;
  pointer-events: none;
}

.photo-tint--green {
  background: linear-gradient(
    145deg,
    rgba(0, 255, 135, 0.4) 0%,
    transparent 45%,
    rgba(255, 0, 110, 0.25) 100%
  );
  mix-blend-mode: soft-light;
}

.photo-tint--gold {
  background: linear-gradient(
    200deg,
    rgba(255, 215, 0, 0.45) 0%,
    transparent 50%,
    rgba(0, 212, 255, 0.3) 100%
  );
  mix-blend-mode: overlay;
}

.photo-tint--magenta {
  background: linear-gradient(
    120deg,
    rgba(255, 0, 110, 0.5) 0%,
    transparent 50%,
    rgba(0, 255, 135, 0.25) 100%
  );
  mix-blend-mode: color-dodge;
}

.photo-closeup__content {
  position: absolute;
  inset: 0;
  z-index: 3;
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  padding: 1.5rem;
}

